#include <iostream>
#include <string>

class Book {
private:
    std::string title;
    std::string author;
    std::string isbn;

public:
    Book(std::string t, std::string a, std::string i) {
        this->title = t;
        this->author = a;
        this->isbn = i;
    }

    std::string getTitle() const {
        return this->title;
    }

    std::string getAuthor() const {
        return this->author;
    }

    std::string getIsbn() const {
        return this->isbn;
    }

    void displayBookInfo() const {
        std::cout << "Book Details:" << std::endl;
        std::cout << "  Title: " << this->title << std::endl;
        std::cout << "  Author: " << this->author << std::endl;
        std::cout << "  ISBN: " << this->isbn << std::endl;
    }
};

int main() {
    Book myBook("The Hitchhiker's Guide to the Galaxy", "Douglas Adams", "978-0345391803");

    myBook.displayBookInfo();

    std::cout << "\nGetter Title: " << myBook.getTitle() << std::endl;
    std::cout << "Getter Author: " << myBook.getAuthor() << std::endl;
    std::cout << "Getter ISBN: " << myBook.getIsbn() << std::endl;

    return 0;
}
